Here's the XAML and ViewModel pattern:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = CurrentItem });

        CurrentItem = null;   // reset so re-selecting the same item works
    }
}
```

### Key bindings explained

| XAML property | ViewModel property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool, TwoWay) | Shows/hides spinner; set `false` when done |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-to-refresh → reloads from API |
| `SelectedItem` | `CurrentItem` (TwoWay) | Tracks which item the user tapped |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on selection → navigates to detail page |
| `ItemsSource` | `Items` (ObservableCollection) | Auto-updates UI on add/remove |

### Important notes

- **Use `ObservableCollection<T>`**, not `List<T>` — otherwise the UI won't update when items change.
- **Set `CurrentItem = null`** after navigation so the same item can be re-selected later.
- **Set `IsRefreshing = false`** in a `finally` block to guarantee the spinner stops even on errors.
- **Never use `ViewCell`** in the template — use `Grid`, `StackLayout`, or any `View` directly.
- Set **`x:DataType`** on `DataTemplate` for compiled bindings and better performance.
